// ---- Pillar 5: Doc Ingester — URL/text → chunks → Jina embeddings → pgvector ----
// Input: { url: '...' }  OR  { content: '...', source: '...', doc_type: '...' }
// 1) If URL: Firecrawl scrape → markdown
// 2) Chunk text (600 chars, 100 overlap, sentence-boundary aware)
// 3) Jina AI embed all chunks (model: jina-embeddings-v2-base-en, 768-dim)
// 4) Batch upsert to Supabase knowledge_base pgvector table
// Cost: Jina free 1M tokens/month — each chunk ~80-150 tokens average
const ENV = (typeof $env !== 'undefined' && $env) ? $env : process.env;
const b = $json.body || $json;

const inputUrl = String(b.url || '').trim();
const inputContent = String(b.content || '').trim();
const source = String(b.source || inputUrl || 'manual').slice(0, 500);
const docType = String(b.doc_type || 'article').slice(0, 50);

if (!inputUrl && !inputContent) return [{ json: { ok: false, error: 'Provide url or content' } }];

// Step 1: Get raw text
let rawText = inputContent;
if (inputUrl && !rawText) {
  if (!ENV.FIRECRAWL_API_KEY) return [{ json: { ok: false, error: 'FIRECRAWL_API_KEY not set — provide content directly' } }];
  try {
    const fcRes = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.firecrawl.dev/v1/scrape',
      headers: { Authorization: `Bearer ${ENV.FIRECRAWL_API_KEY}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ url: inputUrl, formats: ['markdown'], onlyMainContent: true }),
      json: true, timeout: 30000
    });
    rawText = fcRes.data?.markdown || '';
  } catch (e) { return [{ json: { ok: false, error: `Firecrawl failed: ${e.message.slice(0,100)}` } }]; }
}

// Clean markdown noise
rawText = rawText
  .replace(/!\[.*?\]\(.*?\)/g, '')  // images
  .replace(/\[([^\]]+)\]\(.*?\)/g, '$1')  // links → text only
  .replace(/```[\s\S]*?```/g, '')  // code blocks
  .replace(/^#{1,6}\s+/gm, '')  // headings → plain text
  .replace(/\*{1,2}|_{1,2}/g, '')  // bold/italic markers
  .replace(/\n{3,}/g, '\n\n')  // collapse blank lines
  .trim();

if (rawText.length < 100) return [{ json: { ok: false, error: 'Insufficient content after cleaning' } }];

// Step 2: Chunk text (600 chars, 100 overlap, prefer sentence boundaries)
function chunkText(text, maxLen = 600, overlap = 100) {
  const chunks = [];
  let pos = 0;
  while (pos < text.length) {
    let end = pos + maxLen;
    if (end < text.length) {
      // Try to break at sentence end within ±80 chars of end
      const window = text.slice(Math.max(pos, end - 80), Math.min(text.length, end + 80));
      const sentenceEnd = window.search(/[.!?]\s/);
      if (sentenceEnd !== -1) end = Math.max(pos, end - 80) + sentenceEnd + 2;
      else {
        // Fall back to word boundary
        const wordEnd = text.lastIndexOf(' ', end);
        if (wordEnd > pos) end = wordEnd;
      }
    }
    const chunk = text.slice(pos, end).trim();
    if (chunk.length > 50) chunks.push(chunk);
    pos = end - overlap;
  }
  return chunks;
}

const chunks = chunkText(rawText);
if (!chunks.length) return [{ json: { ok: false, error: 'No chunks produced' } }];

// Step 3: Jina AI embeddings — batch up to 8 at a time
if (!ENV.JINA_API_KEY) return [{ json: { ok: false, error: 'JINA_API_KEY not set' } }];

async function embedBatch(texts) {
  const res = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.jina.ai/v1/embeddings',
    headers: { Authorization: `Bearer ${ENV.JINA_API_KEY}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ model: 'jina-embeddings-v2-base-en', input: texts }),
    json: true, timeout: 30000
  });
  return res.data.map(d => d.embedding);
}

const BATCH_SIZE = 8;
const allEmbeddings = [];
for (let i = 0; i < chunks.length; i += BATCH_SIZE) {
  const batch = chunks.slice(i, i + BATCH_SIZE);
  try {
    const embeddings = await embedBatch.call(this, batch);
    allEmbeddings.push(...embeddings);
  } catch (e) {
    return [{ json: { ok: false, error: `Jina embed failed at batch ${i}: ${e.message.slice(0,100)}`, chunks_so_far: allEmbeddings.length } }];
  }
}

// Step 4: Upsert to Supabase knowledge_base
// Supabase doesn't support array upsert with pgvector easily — insert one by one
if (!ENV.SUPABASE_URL) return [{ json: { ok: false, error: 'SUPABASE_URL not set' } }];

const insertResults = await Promise.allSettled(
  chunks.map((chunk, i) =>
    this.helpers.httpRequest({
      method: 'POST',
      url: `${ENV.SUPABASE_URL}/rest/v1/knowledge_base`,
      headers: {
        apikey: ENV.SUPABASE_ANON_KEY, Authorization: `Bearer ${ENV.SUPABASE_ANON_KEY}`,
        'Content-Type': 'application/json', Prefer: 'return=minimal'
      },
      body: JSON.stringify({
        content: chunk,
        source,
        doc_type: docType,
        embedding: allEmbeddings[i]
      }),
      json: false, timeout: 10000
    })
  )
);

const succeeded = insertResults.filter(r => r.status === 'fulfilled').length;

return [{ json: {
  ok: true,
  source, doc_type: docType,
  total_chars: rawText.length,
  chunks_created: chunks.length,
  chunks_stored: succeeded,
  chunks_failed: chunks.length - succeeded
} }];
